TESTS = [
    ("regulated",    "involves regulated or sensitive data (HIPAA, legal, financial)"),
    ("irreversible", "action is irreversible (sends email, publishes, modifies production)"),
    ("relationship", "requires relationship context only the human has"),
    ("verifiable",   "output cannot be verified without doing the work yourself"),
]

def audit_task(task: str, signals: list[str]) -> dict:
    for test_key, test_desc in TESTS:
        if any(test_key in s.lower() for s in signals):
            return {
                "task": task,
                "verdict": "DO NOT DELEGATE",
                "blocking_test": test_desc,
                "reason": f"Task fails: {test_desc}"
            }
    return {
        "task": task,
        "verdict": "DELEGATE",
        "blocking_test": None,
        "reason": "All four tests passed"
    }
